package com.example.myandroid

import android.content.Context
import android.os.Build
import android.os.PowerManager

object HardwareSafetySwitch {
    fun isPhoneSweating(ctx: Context): Boolean {
        try {
            // 1. Thermal Throttling Check (Android 10+)
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
                val pm = ctx.getSystemService(Context.POWER_SERVICE) as PowerManager
                val thermalStatus = pm.currentThermalStatus

                // If it's MODERATE, SEVERE, CRITICAL, or EMERGENCY, the CPU is running hot.
                if (thermalStatus >= PowerManager.THERMAL_STATUS_MODERATE) {
                    DebugLogger.log("SAFETY", "CPU is sweating! Thermal status: $thermalStatus. Aborting.")
                    return true
                }
            }

            // 2. RAM Deadlock Check
            val actManager = ctx.getSystemService(Context.ACTIVITY_SERVICE) as android.app.ActivityManager
            val memInfo = android.app.ActivityManager.MemoryInfo()
            actManager.getMemoryInfo(memInfo)
            if (memInfo.lowMemory) {
                DebugLogger.log("SAFETY", "RAM is critically low. Aborting to save OS.")
                return true
            }
        } catch (e: Exception) {
            // Fail-safe: If we can't read sensors, assume safe to proceed.
        }
        return false
    }
}

